(()=>{"use strict";const data=window.ATHANAS_LEARNING_CONTENT;if(!data)return;const normalize=(value="")=>value.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g,"").replace(/[^a-z0-9]+/g," ").trim();const track=(name,detail={})=>document.dispatchEvent(new CustomEvent("athanas:track",{detail:{name,...detail}}));const entries=[...data.staticSearchEntries,...data.series.flatMap((series)=>series.lessons.map((lesson)=>({category:lesson.status==="published"?"Video Lesson":"Upcoming Lesson",title:lesson.displayTitle,description:lesson.description,url:lesson.status==="published"?lesson.videoUrl:`youtube.html#${series.id}`,external:lesson.status==="published",keywords:`${series.title} ${lesson.title} ${lesson.session} ${lesson.status}`}))),...data.assignments.map((item)=>({category:"Assignment",title:item.title,description:item.description,url:`assignments.html#${item.anchor}`,keywords:`${item.series} practice download submit`})),...data.downloads.map((item)=>({category:"Download",title:item.title,description:item.description,url:item.url,keywords:`${item.category} ${item.type} file resource`})),...data.tools.map((item)=>({category:item.status==="available"?"Learning Tool":"Upcoming Tool",title:item.title,description:item.description,url:item.url||"tools.html",keywords:`${item.level} ${item.purpose} ${item.status}`}))].map((entry)=>({...entry,search:normalize(`${entry.title} ${entry.description} ${entry.keywords || ""} ${entry.category}`)}));function createUi(){if(document.getElementById("siteSearchDialog"))return;const wrap=document.createElement("div");wrap.className="site-search-shell";wrap.innerHTML=`
      <div class="site-search-overlay" id="siteSearchDialog" aria-hidden="true">
        <button class="site-search-backdrop" type="button" aria-label="Close website search"></button>
        <section class="site-search-panel" role="dialog" aria-modal="true" aria-labelledby="siteSearchTitle">
          <header class="site-search-header">
            <div><p class="eyebrow dark">Search Athanas Inspires</p><h2 id="siteSearchTitle">Find anything across the website</h2></div>
            <button class="site-search-close" type="button" aria-label="Close website search">×</button>
          </header>
          <label class="site-search-field"><span class="sr-only">Search lessons, assignments, tools, articles, and pages</span><svg viewBox="0 0 24 24" aria-hidden="true"><circle cx="11" cy="11" r="7"/><path d="m20 20-4-4"/></svg><input id="siteSearchInput" type="search" autocomplete="off" placeholder="Try ‘Excel Session 4’, ‘typing’, or ‘assignment’"></label>
          <div class="site-search-suggestions" aria-label="Popular searches"><button type="button" data-search-suggestion="computer basics">Computer Basics</button><button type="button" data-search-suggestion="microsoft word">Microsoft Word</button><button type="button" data-search-suggestion="excel assignments">Excel Assignments</button><button type="button" data-search-suggestion="typing trainer">Typing Trainer</button></div>
          <div class="site-search-summary" id="siteSearchSummary">Start typing to search the whole platform.</div>
          <div class="site-search-results" id="siteSearchResults" role="listbox" aria-live="polite"></div>
        </section>
      </div>`;document.body.appendChild(wrap);}
function addNavButton(){const nav=document.querySelector(".nav-links");if(!nav||nav.querySelector(".nav-site-search-item"))return;const item=document.createElement("li");item.className="nav-site-search-item";item.innerHTML='<button class="nav-site-search-btn" type="button" data-site-search-open aria-label="Search Athanas Inspires"><svg viewBox="0 0 24 24" aria-hidden="true"><circle cx="11" cy="11" r="7"/><path d="m20 20-4-4"/></svg><span>Search</span></button>';const support=nav.querySelector(".nav-dropdown-support");if(support?.parentElement===nav)nav.insertBefore(item,support);else nav.appendChild(item);}
let lastFocus=null;function openSearch(seed=""){createUi();const overlay=document.getElementById("siteSearchDialog");const input=document.getElementById("siteSearchInput");lastFocus=document.activeElement;overlay.classList.add("is-open");overlay.setAttribute("aria-hidden","false");document.body.classList.add("site-search-open");input.value=seed;render(seed);setTimeout(()=>input.focus(),50);track("search_open",{label:seed?"Homepage search":"Navigation search"});}
function closeSearch(){const overlay=document.getElementById("siteSearchDialog");if(!overlay)return;overlay.classList.remove("is-open");overlay.setAttribute("aria-hidden","true");document.body.classList.remove("site-search-open");lastFocus?.focus?.({preventScroll:true});}
function score(entry,query){const terms=normalize(query).split(" ").filter(Boolean);if(!terms.length)return 0;let total=0;terms.forEach((term)=>{if(normalize(entry.title).includes(term))total+=8;if(normalize(entry.category).includes(term))total+=4;if(entry.search.includes(term))total+=2;});if(entry.search.includes(normalize(query)))total+=12;return total;}
function render(query){const results=document.getElementById("siteSearchResults");const summary=document.getElementById("siteSearchSummary");if(!results||!summary)return;const clean=query.trim();if(!clean){results.innerHTML="";summary.textContent="Start typing to search the whole platform.";return;}
const matches=entries.map((entry)=>({entry,score:score(entry,clean)})).filter((item)=>item.score>0).sort((a,b)=>b.score-a.score||a.entry.title.localeCompare(b.entry.title)).slice(0,18);summary.textContent=matches.length?`${matches.length} result${matches.length === 1 ? "" : "s"} found for “${clean}”.`:`No results found for “${clean}”. Try a shorter phrase.`;results.innerHTML=matches.map(({entry})=>`<a class="site-search-result" role="option" href="${entry.url}"${entry.external || /^https?:/.test(entry.url) ? ' target="_blank" rel="noopener noreferrer"' : ""} data-search-result data-track="search_result_open" data-track-label="${entry.title.replace(/"/g, "&quot;")}"><span class="site-search-category">${entry.category}</span><strong>${entry.title}</strong><p>${entry.description}</p><span class="site-search-arrow" aria-hidden="true">→</span></a>`).join("");track("search_performed",{label:clean,value:matches.length});}
document.addEventListener("DOMContentLoaded",()=>{createUi();addNavButton();const overlay=document.getElementById("siteSearchDialog");const input=document.getElementById("siteSearchInput");overlay.querySelector(".site-search-close")?.addEventListener("click",closeSearch);overlay.querySelector(".site-search-backdrop")?.addEventListener("click",closeSearch);input?.addEventListener("input",()=>render(input.value));overlay.querySelectorAll("[data-search-suggestion]").forEach((button)=>button.addEventListener("click",()=>{input.value=button.dataset.searchSuggestion;render(input.value);input.focus();}));const params=new URLSearchParams(window.location.search);const requestedSearch=params.get("search");if(requestedSearch)setTimeout(()=>openSearch(requestedSearch),120);const homeInput=document.getElementById("homeSearch");if(homeInput){homeInput.dataset.searchMode="global";homeInput.placeholder="Search the whole website...";homeInput.addEventListener("focus",()=>openSearch(homeInput.value));homeInput.addEventListener("click",()=>openSearch(homeInput.value));document.getElementById("clearSearch")?.addEventListener("click",()=>{homeInput.value="";openSearch();});}});document.addEventListener("click",(event)=>{if(event.target.closest("[data-site-search-open]"))openSearch();if(event.target.closest("[data-search-result]"))closeSearch();});document.addEventListener("keydown",(event)=>{if(event.key==="Escape"&&document.body.classList.contains("site-search-open"))closeSearch();if((event.ctrlKey||event.metaKey)&&event.key.toLowerCase()==="k"){event.preventDefault();openSearch();}});})();